func catalanNumbers(_ n: Int) -> Int {
    let MOD: Int64 = 1000000007

    func modPow(_ base: Int64, _ exp: Int64, _ mod: Int64) -> Int64 {
        var result: Int64 = 1
        var b = base % mod
        var e = exp
        while e > 0 {
            if e % 2 == 1 { result = result * b % mod }
            e /= 2
            b = b * b % mod
        }
        return result
    }

    func modInv(_ a: Int64, _ mod: Int64) -> Int64 {
        return modPow(a, mod - 2, mod)
    }

    var result: Int64 = 1
    for i in 1...max(1, n) {
        if n == 0 { break }
        result = result * Int64(2 * (2 * i - 1)) % MOD
        result = result * modInv(Int64(i + 1), MOD) % MOD
    }

    return Int(result)
}

export function catalanNumbers(n: number): number {
    const MOD = 1000000007n;

    function modPow(base: bigint, exp: bigint, mod: bigint): bigint {
        let result = 1n;
        base %= mod;
        while (exp > 0n) {
            if (exp % 2n === 1n) result = result * base % mod;
            exp /= 2n;
            base = base * base % mod;
        }
        return result;
    }

    function modInv(a: bigint, mod: bigint): bigint {
        return modPow(a, mod - 2n, mod);
    }

    let result = 1n;
    for (let i = 1; i <= n; i++) {
        result = result * BigInt(2 * (2 * i - 1)) % MOD;
        result = result * modInv(BigInt(i + 1), MOD) % MOD;
    }

    return Number(result);
}
